/**
 * Extract TrueMoney voucher hash from link or return the link itself
 */
function extractVoucherCode(link: string): string | null {
    // Try to extract hash from URL
    const regex = /gift\.truemoney\.com\/campaign\/\?v=([A-Za-z0-9]+)/
    const match = link.match(regex)
    if (match) {
        return match[1]
    }
    // If no match, assume the link itself is the code
    if (link.trim().length > 0) {
        return link.trim()
    }
    return null
}

